import React, { useState, useEffect } from 'react';
//import './ProductsPage.css';

const ProductsPage = ({
	products,
	searchQuery,
	setSearchQuery,
	setCartItems,
	user,
	addToCart,
	setCurrentPage,
	setLoading,
	setError
}) => {
	const [filteredProducts, setFilteredProducts] = useState([]);
	const [currentSlide, setCurrentSlide] = useState(0);
	const [selectedCategory, setSelectedCategory] = useState('all');
	const [sortBy, setSortBy] = useState('featured');

	const offerBanners = [
		{ id: 1, title: 'MEGA SALE', discount: '50% OFF', color: 'from-red-500 to-red-600' },
		{ id: 2, title: 'LIMITED TIME', discount: 'Upto 70% OFF', color: 'from-teal-500 to-teal-600' },
		{ id: 3, title: 'FLASH DEAL', discount: 'Extra 20% OFF', color: 'from-yellow-500 to-yellow-600' },
		{ id: 4, title: 'NEW YEAR SPECIAL', discount: 'Flat ₹1000 OFF', color: 'from-green-500 to-green-600' }
	];

	useEffect(() => {
		const timer = setInterval(() => {
			setCurrentSlide((prev) => (prev + 1) % offerBanners.length);
		}, 4000);
		return () => clearInterval(timer);
	}, [offerBanners.length]);

	useEffect(() => {
		let result = products || [];

		if (searchQuery) {
			result = result.filter(p =>
				p.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
				p.description?.toLowerCase().includes(searchQuery.toLowerCase())
			);
		}

		if (selectedCategory !== 'all') {
			result = result.filter(p => p.category?.toLowerCase() === selectedCategory.toLowerCase());
		}

		switch (sortBy) {
			case 'price-low':
				result.sort((a, b) => a.price - b.price);
				break;
			case 'price-high':
				result.sort((a, b) => b.price - a.price);
				break;
			case 'rating':
				result.sort((a, b) => (b.rating || 0) - (a.rating || 0));
				break;
			default:
				break;
		}

		setFilteredProducts(result);
	}, [products, searchQuery, selectedCategory, sortBy]);

	const handleAddToCart = async (product) => {
		try {
			setLoading(true);
			await addToCart({
				productId: product.productId || product.id,
				quantity: 1
			});
			setError('');
		} catch (err) {
			setError('Failed to add item to cart');
			console.error(err);
		} finally {
			setLoading(false);
		}
	};

	const categories = ['all', 'Electronics', 'Fashion', 'Home', 'Books', 'Sports'];

	return (
		<div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50">
			{/* Header */}
			<header className="max-w-7xl mx-auto px-6 py-6 flex items-center justify-between border-b">
				<h1 className="text-2xl font-extrabold text-gray-900">Welcome, {user?.fullName || 'Customer'}!</h1>
				<div className="flex items-center gap-2 bg-white border rounded-lg px-4 py-2 shadow-sm">
					<input
						type="text"
						placeholder="Search products..."
						value={searchQuery}
						onChange={(e) => setSearchQuery(e.target.value)}
						className="outline-none bg-transparent text-sm w-64"
					/>
					<button className="text-gray-400 hover:text-gray-600">🔍</button>
				</div>
			</header>

			{/* Sliding Offer Banner */}
			<section className="max-w-7xl mx-auto px-6 py-6">
				<div className="relative h-40 rounded-2xl overflow-hidden shadow-lg">
					{offerBanners.map((banner, index) => (
						<div
							key={banner.id}
							className={`absolute inset-0 bg-gradient-to-r ${banner.color} flex items-center justify-center transition-opacity duration-500 ${
								index === currentSlide ? 'opacity-100' : 'opacity-0'
							}`}
						>
							<div className="text-center text-white">
								<h2 className="text-4xl font-extrabold mb-2">{banner.title}</h2>
								<p className="text-2xl font-bold mb-4">{banner.discount}</p>
								<button className="px-6 py-2 bg-white text-gray-900 font-semibold rounded-lg hover:shadow-lg">
									Shop Now
								</button>
							</div>
						</div>
					))}

					{/* Carousel Controls */}
					<div className="absolute bottom-4 left-1/2 transform -translate-x-1/2 flex gap-2">
						{offerBanners.map((_, index) => (
							<button
								key={index}
								className={`w-3 h-3 rounded-full transition-all ${
									index === currentSlide ? 'bg-white w-8' : 'bg-white/50'
								}`}
								onClick={() => setCurrentSlide(index)}
							/>
						))}
					</div>
				</div>
			</section>

			{/* Filters & Sorting */}
			<section className="max-w-7xl mx-auto px-6 py-6 space-y-4">
				<div>
					<h3 className="text-lg font-bold mb-3">Categories</h3>
					<div className="flex flex-wrap gap-2">
						{categories.map(cat => (
							<button
								key={cat}
								className={`px-4 py-2 rounded-lg font-medium transition-all ${
									selectedCategory === cat
										? 'bg-blue-600 text-white shadow-md'
										: 'bg-white border text-gray-700 hover:shadow'
								}`}
								onClick={() => setSelectedCategory(cat)}
							>
								{cat.charAt(0).toUpperCase() + cat.slice(1)}
							</button>
						))}
					</div>
				</div>

				<div className="flex justify-between items-center">
					<p className="text-gray-600 font-medium">Showing {filteredProducts.length} products</p>
					<div className="flex items-center gap-2">
						<label className="font-medium text-gray-700">Sort By:</label>
						<select
							value={sortBy}
							onChange={(e) => setSortBy(e.target.value)}
							className="px-4 py-2 border rounded-lg bg-white text-gray-700 hover:shadow"
						>
							<option value="featured">Featured</option>
							<option value="price-low">Price: Low to High</option>
							<option value="price-high">Price: High to Low</option>
							<option value="rating">Highest Rating</option>
						</select>
					</div>
				</div>
			</section>

			{/* Products Grid */}
			<section className="max-w-7xl mx-auto px-6 py-8">
				{filteredProducts.length > 0 ? (
					<div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
						{filteredProducts.map(product => (
							<div key={product.id || product.productId} className="bg-white rounded-xl shadow-sm hover:shadow-lg transition-shadow overflow-hidden">
								<div className="relative h-48 bg-gray-100 overflow-hidden">
									<img
										src={product.imageUrl || '🖼️'}
										alt={product.name}
										onError={(e) => (e.target.src = '🖼️')}
										className="w-full h-full object-cover hover:scale-105 transition-transform"
									/>
									{product.discount && (
										<span className="absolute top-3 right-3 bg-red-500 text-white px-3 py-1 rounded-full text-sm font-bold">
											{product.discount}% OFF
										</span>
									)}
								</div>

								<div className="p-4 space-y-3">
									<h3 className="font-semibold text-gray-900 line-clamp-2">{product.name}</h3>
									<p className="text-sm text-gray-500 line-clamp-1">{product.description?.substring(0, 50)}...</p>

									<div className="flex items-center gap-2">
										<span className="text-yellow-500">{'⭐'.repeat(Math.min(product.rating || 4, 5))}</span>
										<span className="text-xs text-gray-500">({product.reviews || 0})</span>
									</div>

									<div className="flex items-center gap-2">
										<span className="text-xl font-bold text-blue-600">₹{product.price}</span>
										{product.originalPrice && (
											<span className="text-sm text-gray-400 line-through">₹{product.originalPrice}</span>
										)}
									</div>

									<button
										className="w-full py-2 bg-green-600 text-white font-semibold rounded-lg hover:bg-green-700 transition-colors"
										onClick={() => handleAddToCart(product)}
									>
										🛒 Add to Cart
									</button>
								</div>
							</div>
						))}
					</div>
				) : (
					<div className="text-center py-16">
						<p className="text-gray-500 text-lg">No products found. Try adjusting your filters.</p>
					</div>
				)}
			</section>
		</div>
	);
};

export default ProductsPage;
